// Build the digest text and per-package texts
const input = $input.first().json;
const run_id = input.run_id || 'unknown';
const mode = input.mode || 'UNKNOWN';
const shortlist = Array.isArray(input.shortlist) ? input.shortlist : [];
const packages = Array.isArray(input.content_packages) ? input.content_packages : [];
const meta = input.meta || {};
const note = input.note || '';

const todayIT = new Intl.DateTimeFormat('it-IT', { dateStyle:'full', timeZone:'Europe/Rome' }).format(new Date());

function esc(s=''){ return String(s).replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

let digest = `<b>AI Daily Digest</b> — ${esc(todayIT)}\n`;
digest += `Mode: <code>${esc(mode)}</code> | run: <code>${esc(run_id)}</code>\n\n`;
if (shortlist.length) {
  digest += `<b>Shortlist (top topic):</b>\n`;
  shortlist.slice(0,5).forEach((s,i) => {
    const title = esc(s.title || s);
    const reason = s.reason ? ` — <i>${esc(s.reason)}</i>` : '';
    digest += `${i+1}. ${title}${reason}\n`;
  });
  digest += '\n';
} else {
  digest += `<i>Nessun elemento in shortlist.</i>\n\n`;
}
if (mode === 'FALLBACK' || mode === 'HYBRID') {
  digest += `ℹ️ Fallback attivo: uso editoriale evergreen/trend.\n`;
}
if (mode === 'MONITOR_ONLY') {
  digest += `⚠️ Giornata debole. Solo segnali monitorati, nessun pacchetto.\n`;
}
if (mode === 'HARD_STOP') {
  digest += `🛑 HARD_STOP — verifica i log.\n`;
}
if (note) digest += `\n${esc(note)}\n`;
digest += `\nSources: ${meta.sources_total||0} (failed ${meta.sources_failed||0}) · raw ${meta.raw_items_count||0} · deduped ${meta.deduped_count||0} · selected ${meta.selected_count||0}`;

// Per-package messages
function pkgText(p){
  const ig = p.instagram || {};
  const li = p.linkedin || {};
  let t = '';
  t += `<b>📦 ${esc(p.topic || p.title || 'Pacchetto')}</b>\n`;
  t += `Status: <code>${esc(p.status||'raw')}</code> · Confidence: <code>${esc(p.confidence_label||'n/a')}</code>\n`;
  if (p.recording_time_estimate) t += `Recording: ${esc(p.recording_time_estimate)}\n`;
  if (p.why_it_matters) t += `\n<b>Perché conta:</b> ${esc(p.why_it_matters)}\n`;
  if (p.why_it_can_work) t += `<b>Perché può funzionare:</b> ${esc(p.why_it_can_work)}\n`;
  t += `\n<b>🎬 Instagram</b>\n`;
  if (ig.hook)    t += `<b>Hook:</b> ${esc(ig.hook)}\n`;
  if (ig.script)  t += `<b>Script:</b>\n${esc(ig.script)}\n`;
  if (ig.caption) t += `<b>Caption:</b> ${esc(ig.caption)}\n`;
  if (ig.cta)     t += `<b>CTA:</b> ${esc(ig.cta)}\n`;
  t += `\n<b>💼 LinkedIn</b>\n`;
  if (li.post)          t += `${esc(li.post)}\n`;
  if (li.take_personal) t += `\n<i>Take personale:</i> ${esc(li.take_personal)}\n`;
  if (p.source_name || p.source_url) {
    t += `\n<b>Fonte:</b> ${esc(p.source_name||'')} ${p.source_url?`— ${esc(p.source_url)}`:''}`;
  }
  return t;
}

// Split long messages (Telegram limit 4096)
function chunk(s, n=3800){
  const out=[]; let i=0; while (i<s.length){ out.push(s.slice(i,i+n)); i+=n; } return out;
}

const messages = [];
chunk(digest).forEach(t => messages.push({ kind:'digest', text: t }));
packages.forEach((p, idx) => {
  chunk(pkgText(p)).forEach(t => messages.push({ kind:'package', idx, text: t, content_id: p.content_id }));
});

return messages.map(m => ({ json: { ...m, run_id, mode, meta, started_at: input.started_at, packages_count: packages.length } }));

// Aggregate delivery status across all sent messages and emit a single row
// with column keys matching the run_logs schema (autoMap-friendly).
const items = $input.all();
let ok=0, fail=0;
for (const it of items){
  if (it.json && it.json.error) fail++; else ok++;
}
const first = items[0]?.json || {};
const status = fail === 0 ? 'delivered' : (ok > 0 ? 'partial' : 'delivery_failed');
const meta = first.meta || {};
const started_at = first.started_at || new Date().toISOString();
const ended_at = new Date().toISOString();
return [{ json: {
  run_id: first.run_id || 'unknown',
  run_date: (new Date()).toISOString().slice(0,10),
  mode: first.mode || 'UNKNOWN',
  sources_total: meta.sources_total || 0,
  sources_failed: meta.sources_failed || 0,
  raw_items_count: meta.raw_items_count || 0,
  deduped_count: meta.deduped_count || 0,
  selected_count: meta.selected_count || 0,
  telegram_status: status,
  notes: `ok=${ok} fail=${fail} packages=${first.packages_count||0}`,
  started_at,
  ended_at
}}];
